const SectionTitle = ({ icon, title }: { icon: string; title: string }) => {
  return (
    <div className="flex items-center gap-2 mb-4">
      <span className="text-xl">{icon}</span>
      <h3 className="text-lg font-bold text-foreground tracking-tight">{title}</h3>
    </div>
  );
};

// Checkbox Component
const Checkbox = ({ 
  label, 
  checked, 
  onChange 
}: { 
  label: string; 
  checked: boolean; 
  onChange: (checked: boolean) => void 
}) => {
  return (
    <label className="flex items-center gap-2.5 cursor-pointer group select-none">
      <div 
        className={cn(
          "w-5 h-5 rounded-md border flex items-center justify-center transition-all duration-200",
          checked 
            ? "bg-primary border-primary text-primary-foreground" 
            : "bg-background border-input-border group-hover:border-primary/50"
        )}
      >
        {checked && <Check size={14} strokeWidth={3} />}
      </div>
      <span className={cn("text-[15px] transition-colors", checked ? "text-foreground font-medium" : "text-muted-foreground group-hover:text-foreground")}>
        {label}
      </span>
      <input 
        type="checkbox" 
        className="hidden" 
        checked={checked} 
        onChange={(e) => onChange(e.target.checked)} 
      />
    </label>
  );
};

// Select Component
const Select = ({ 
  label, 
  value, 
  options, 
  onChange 
}: { 
  label?: string;
  value: string; 
  options: string[]; 
  onChange: (val: string) => void 
}) => {
  return (
    <div className="flex flex-col gap-1.5 w-full">
      {label && <span className="text-xs font-medium text-muted-foreground ml-1">{label}</span>}
      <div className="relative">
        <select
          value={value}
          onChange={(e) => onChange(e.target.value)}
          className="w-full appearance-none bg-input-background hover:bg-accent/50 transition-colors rounded-xl px-3 py-3 text-[15px] font-medium text-foreground pr-8 focus:outline-none focus:ring-2 focus:ring-primary/10 border-none cursor-pointer"
        >
          {options.map((opt) => (
            <option key={opt} value={opt}>{opt}</option>
          ))}
        </select>
        <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground pointer-events-none" size={16} />
      </div>
    </div>
  );
};

// Input Component
const Input = ({ 
  placeholder, 
  value, 
  onChange 
}: { 
  placeholder: string; 
  value: string; 
  onChange: (val: string) => void 
}) => {
  return (
    <input
      type="text"
      value={value}
      onChange={(e) => onChange(e.target.value)}
      placeholder={placeholder}
      className="w-full bg-transparent border-b border-border py-2.5 text-[15px] placeholder:text-muted-foreground/70 focus:outline-none focus:border-primary transition-colors"
    />
  );
};

// Toggle Component
const Toggle = ({ 
  label, 
  checked, 
  onChange 
}: { 
  label: string; 
  checked: boolean; 
  onChange: (checked: boolean) => void 
}) => {
  return (
    <div className="flex items-center justify-between py-1">
      <span className="text-[15px] font-medium text-foreground">{label}</span>
      <button
        onClick={() => onChange(!checked)}
        className={cn(
          "w-11 h-6 rounded-full relative transition-colors duration-200 focus:outline-none",
          checked ? "bg-primary" : "bg-muted"
        )}
      >
        <div 
          className={cn(
            "w-5 h-5 bg-white rounded-full absolute top-0.5 shadow-sm transition-transform duration-200",
            checked ? "left-[calc(100%-1.375rem)]" : "left-0.5"
          )}
        />
      </button>
    </div>
  );
};

// --- Main Application ---

export function PetLog() {
  // 1. Condition
  const [appetite, setAppetite] = useState('보통');
  const [vitality, setVitality] = useState('활발');
  const [stool, setStool] = useState('정상');
  const [conditionChecks, setConditionChecks] = useState<Record<string, boolean>>({
    '구토': false, '기침/재채기': false, '눈물': false, '가려움': false, '절뚝임': false, '물 많이 마심': false
  });
  const [conditionMemo, setConditionMemo] = useState('');

  // 2. Behavior
  const [behaviorChecks, setBehaviorChecks] = useState<Record<string, boolean>>({
    '평소와 같음': true, '짖음/울음 증가': false, '과민/흥분': false, '숨기': false, '파괴 행동': false, '집착': false
  });
  const [externalReaction, setExternalReaction] = useState('보통');
  const [behaviorMemo, setBehaviorMemo] = useState('');

  // 3. Interaction
  const [reactionPeople, setReactionPeople] = useState('좋음');
  const [reactionAnimals, setReactionAnimals] = useState('보통');
  const [interactionChecks, setInteractionChecks] = useState<Record<string, boolean>>({
    '분리불안 의심': false, '낯가림': false, '경계': false
  });
  const [interactionMemo, setInteractionMemo] = useState('');

  // 4. Training
  const [trainingChecks, setTrainingChecks] = useState<Record<string, boolean>>({
    '앉아': false, '기다려': false, '이리와': false, '화장실': false, '리드줄 매너': false
  });
  const [trainingResult, setTrainingResult] = useState('성공');
  const [trainingMemo, setTrainingMemo] = useState('');

  // 5. Health
  const [healthChecks, setHealthChecks] = useState<Record<string, boolean>>({
    '눈': false, '귀': false, '피부': false, '발': false, '치아': false
  });
  const [weightFeeling, setWeightFeeling] = useState('없음');
  const [healthMemo, setHealthMemo] = useState('');

  // 6. Notes (Expandable)
  const [isNotesExpanded, setIsNotesExpanded] = useState(false);
  const [notes, setNotes] = useState('');

  const toggleCheck = (state: Record<string, boolean>, setter: any, key: string) => {
    setter({ ...state, [key]: !state[key] });
  };

  return (
    <div className="w-full min-h-screen bg-[#F8F9FA] pb-24">
      <div className="max-w-[390px] mx-auto bg-background min-h-screen relative shadow-2xl">

        {/* Header */}
        <header className="pt-12 pb-6 px-6 bg-background sticky top-0 z-10 border-b border-border/40 backdrop-blur-md bg-background/80">
          <h1 className="text-2xl font-bold text-foreground">애완동물 관찰일기 <span className="text-primary font-light">|</span> Pet Log</h1>
          <p className="text-muted-foreground text-sm mt-1">오늘의 상태를 간단히 기록하세요.</p>
        </header>

        <div className="p-5 flex flex-col gap-5">

          {/* 1. Condition */}
          <Card>
            <SectionTitle icon="🐾" title="컨디션" />

            <div className="grid grid-cols-3 gap-2 mb-5">
              <Select label="식욕" value={appetite} options={['좋음', '보통', '나쁨']} onChange={setAppetite} />
              <Select label="활력" value={vitality} options={['활발', '보통', '저조']} onChange={setVitality} />
              <Select label="배변" value={stool} options={['정상', '설사', '변비']} onChange={setStool} />
            </div>

            <div className="grid grid-cols-2 gap-y-3 gap-x-2 mb-4">
              {Object.keys(conditionChecks).map(key => (
                <Checkbox 
                  key={key} 
                  label={key} 
                  checked={conditionChecks[key]} 
                  onChange={() => toggleCheck(conditionChecks, setConditionChecks, key)} 
                />
              ))}
            </div>

            <Input 
              placeholder="예: 산책 후 약간 지쳐 보임" 
              value={conditionMemo} 
              onChange={setConditionMemo} 
            />
          </Card>

          {/* 2. Behavior Observation */}
          <Card>
            <SectionTitle icon="👀" title="행동 관찰" />

            <div className="grid grid-cols-2 gap-y-3 gap-x-2 mb-5">
              {Object.keys(behaviorChecks).map(key => (
                <Checkbox 
                  key={key} 
                  label={key} 
                  checked={behaviorChecks[key]} 
                  onChange={() => toggleCheck(behaviorChecks, setBehaviorChecks, key)} 
                />
              ))}
            </div>

            <div className="mb-4">
              <Select 
                label="외부 반응" 
                value={externalReaction} 
                options={['차분', '보통', '흥분', '통제어려움']} 
                onChange={setExternalReaction} 
              />
            </div>

            <Input 
              placeholder="예: 초인종 소리에 평소보다 예민하게 반응함" 
              value={behaviorMemo} 
              onChange={setBehaviorMemo} 
            />
          </Card>

          {/* 3. Interaction */}
          <Card>
            <SectionTitle icon="💕" title="상호작용" />

            <div className="flex gap-3 mb-5">
              <Select label="사람 반응" value={reactionPeople} options={['좋음', '보통', '경계', '공격']} onChange={setReactionPeople} />
              <Select label="다른 동물 반응" value={reactionAnimals} options={['좋음', '보통', '경계', '공격']} onChange={setReactionAnimals} />
            </div>

            <div className="flex flex-col gap-3 mb-4">
              {Object.keys(interactionChecks).map(key => (
                <Checkbox 
                  key={key} 
                  label={key} 
                  checked={interactionChecks[key]} 
                  onChange={() => toggleCheck(interactionChecks, setInteractionChecks, key)} 
                />
              ))}
            </div>

            <Input 
              placeholder="예: 낯선 강아지와 잘 어울려 놀았음" 
              value={interactionMemo} 
              onChange={setInteractionMemo} 
            />
          </Card>

          {/* 4. Training/Habit */}
          <Card>
            <SectionTitle icon="🎓" title="훈련 / 습관" />

            <div className="grid grid-cols-2 gap-y-3 gap-x-2 mb-5">
              {Object.keys(trainingChecks).map(key => (
                <Checkbox 
                  key={key} 
                  label={key} 
                  checked={trainingChecks[key]} 
                  onChange={() => toggleCheck(trainingChecks, setTrainingChecks, key)} 
                />
              ))}
            </div>

            <div className="mb-4">
              <Select 
                label="성취도" 
                value={trainingResult} 
                options={['성공', '부분성공', '실패', '미실시']} 
                onChange={setTrainingResult} 
              />
            </div>

            <Input 
              placeholder="예: 간식 없이 '앉아' 성공함" 
              value={trainingMemo} 
              onChange={setTrainingMemo} 
            />
          </Card>

          {/* 5. Health Check */}
          <Card>
            <SectionTitle icon="🩺" title="건강 체크" />

            <p className="text-xs text-muted-foreground mb-3 font-medium">이상이 있는 부위를 선택하세요</p>
            <div className="grid grid-cols-3 gap-y-3 gap-x-2 mb-5">
              {Object.keys(healthChecks).map(key => (
                <Checkbox 
                  key={key} 
                  label={key} 
                  checked={healthChecks[key]} 
                  onChange={() => toggleCheck(healthChecks, setHealthChecks, key)} 
                />
              ))}
            </div>

            <div className="mb-4">
              <Select 
                label="체중 변화 느낌" 
                value={weightFeeling} 
                options={['없음', '약간', '보통', '심함']} 
                onChange={setWeightFeeling} 
              />
            </div>

            <Input 
              placeholder="예: 왼쪽 뒷다리를 약간 저는 듯함" 
              value={healthMemo} 
              onChange={setHealthMemo} 
            />
          </Card>

          {/* 6. Notes (Optional) */}
          <div className="border border-dashed border-border rounded-[20px] bg-background/50 overflow-hidden">
            <button 
              onClick={() => setIsNotesExpanded(!isNotesExpanded)}
              className="w-full p-5 flex items-center justify-between hover:bg-muted/30 transition-colors"
            >
              <div className="flex items-center gap-2">
                <span className="text-xl">📝</span>
                <span className="font-bold text-foreground">느낀 점 (선택)</span>
              </div>
              <div className="flex items-center gap-1 text-primary text-sm font-medium">
                {isNotesExpanded ? '접기' : '추가로 기록하기'}
                {isNotesExpanded ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
