                >
                  <div className="px-5 pb-5">
                    <textarea 
                      className="w-full bg-input-background rounded-xl p-4 text-[15px] resize-none focus:outline-none focus:ring-2 focus:ring-primary/10 min-h-[100px]"
                      placeholder="오늘 하루 애완동물과 함께하며 느낀 점을 자유롭게 기록하세요. 예: 오늘은 공원에서 정말 행복해 보였다."
                      value={notes}
                      onChange={(e) => setNotes(e.target.value)}
                    />
                  </div>
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        </div>

        {/* Fixed Bottom Button */}
        <div className="fixed bottom-0 left-0 right-0 p-5 bg-gradient-to-t from-background via-background to-transparent z-20 flex justify-center pointer-events-none">
          <button className="w-full max-w-[350px] bg-primary text-primary-foreground font-bold py-4 rounded-2xl shadow-lg shadow-primary/20 flex items-center justify-center gap-2 active:scale-[0.98] transition-all pointer-events-auto">
            <Save size={20} />
            저장하기
          </button>
        </div>

      </div>
    </div>
  );
}
